.darma-loader-darma-custom-410 {
  width: 50px;
  aspect-ratio: 1;
  color: var(--loader-color, #db2777);
  border: 2px solid;
  display: grid;
  box-sizing: border-box;
  animation: darma-loader-darma-custom-410-l1 4s infinite linear;
}.darma-loader-darma-custom-410::before,.darma-loader-darma-custom-410::after {content: "";
  grid-area: 1/1;
  margin: auto;
  width: 70.7%;
  aspect-ratio: 1;
  border: 2px solid;
  box-sizing: content-box;
  animation: inherit;
}.darma-loader-darma-custom-410::after {width: 50%;
  aspect-ratio: 1;
  border: 2px solid;
  animation-duration: 2s;
}@keyframes darma-loader-darma-custom-410-l1{100% {transform: rotate(1turn)}}

